import React, { useState } from 'react';

const FormularioOferta = ({ onSave, onCancel }) => {
  const [formData, setFormData] = useState({
    producto: '', 
    precioViejo: '', 
    precioNuevo: '', 
    peso: '',
    stock: '' // Nuevo campo
  });

  const handleSubmit = (e) => {
    e.preventDefault();
    onSave({ 
      ...formData, 
      id: Date.now(), // ID único para el producto
      precioViejo: Number(formData.precioViejo),
      precioNuevo: Number(formData.precioNuevo),
      peso: parseFloat(formData.peso), // Asegura decimales
      stock: parseInt(formData.stock) 
    });
  };

  return (
    <div style={formCard}>
      <h3 style={{marginTop: 0}}>Nueva Oferta</h3>
      <form onSubmit={handleSubmit}>
        <input placeholder="Nombre del producto" style={inputStyle} required 
          onChange={e => setFormData({...formData, producto: e.target.value})} />
        
        <div style={{ display: 'flex', gap: '10px' }}>
          <input type="number" placeholder="Precio Normal" style={inputStyle} required 
            onChange={e => setFormData({...formData, precioViejo: e.target.value})} />
          <input type="number" placeholder="Precio Oferta" style={inputStyle} required 
            onChange={e => setFormData({...formData, precioNuevo: e.target.value})} />
        </div>

        <div style={rowStyle}>
          <div style={{ flex: 1 }}>
            <label style={miniLabel}>Peso (kg) - Ej: 0.165</label>
            {/* step="0.001" permite 3 decimales para los gramos */}
            <input type="number" step="0.001" placeholder="0.000" style={inputStyle} required 
              onChange={e => setFormData({...formData, peso: e.target.value})} />
          </div>
          <div style={{ flex: 1 }}>
            <label style={miniLabel}>Unidades en Stock</label>
            <input type="number" placeholder="Ej: 20" style={inputStyle} required 
              onChange={e => setFormData({...formData, stock: e.target.value})} />
          </div>
        </div>

        <div style={{ display: 'flex', gap: '10px', marginTop: '10px' }}>
          <button type="submit" style={btnSave}>Publicar Oferta</button>
          <button type="button" onClick={onCancel} style={btnCancel}>Cancelar</button>
        </div>
      </form>
    </div>
  );
};

const formCard = { background: 'white', padding: '25px', borderRadius: '15px', border: '1px solid #e2e8f0' };
const inputStyle = { width: '100%', padding: '12px', marginBottom: '10px', borderRadius: '8px', border: '1px solid #ddd', boxSizing: 'border-box' };
const rowStyle = { display: 'flex', gap: '15px', marginBottom: '10px', background: '#f8fafc', padding: '10px', borderRadius: '10px' };
const miniLabel = { fontSize: '0.75rem', color: '#64748b', display: 'block', marginBottom: '5px' };
const btnSave = { flex: 1, padding: '12px', background: '#e67e22', color: 'white', border: 'none', borderRadius: '10px', fontWeight: 'bold', cursor: 'pointer' };
const btnCancel = { flex: 1, padding: '12px', background: '#f1f5f9', color: '#64748b', border: 'none', borderRadius: '10px', cursor: 'pointer' };

export default FormularioOferta;
